#!/usr/bin/env python3
"""socketscope - Linux socket & process graph explorer.

Snapshots every open socket and the processes using them (plus the process
tree) straight from /proc, then writes ONE self-contained, offline, interactive
HTML force-directed graph for exploring it.

Stdlib only - no external Python packages. Cytoscape.js is vendored inline
(gzip+base64 blob, decompressed at runtime) so the emitted HTML opens offline
in any browser with no network access.

Usage:
    sudo python3 socketscope.py              # full process<->socket visibility
    python3 socketscope.py -o sockets.html   # works unprivileged (own procs only)

It is a point-in-time snapshot; re-run to refresh.
"""
import os
import sys
import pwd
import grp
import json
import socket
import stat
import gzip
import base64
import argparse
import datetime

# --- vendored cytoscape.min.js (gzip -> base64); decompressed at emit time ---
# License URLs inside the bundle's comments are defanged (hxxp://) so the
# emitted HTML carries zero literal http(s) references; attribution preserved.
CYTO_B64 = ""


def cyto_js():
    return gzip.decompress(base64.b64decode(CYTO_B64)).decode("utf-8")


